import{_ as t,o as e,c as i,a2 as d}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Random Image API dan Public Gallery","description":"","frontmatter":{},"headers":[],"relativePath":"id-ID/Other/random-image-api-and-public-gallery.md","filePath":"id-ID/Other/random-image-api-and-public-gallery.md","lastUpdated":1781962217000}'),n={name:"id-ID/Other/random-image-api-and-public-gallery.md"};function r(l,a,o,s,c,u){return e(),i("div",null,[...a[0]||(a[0]=[d(`<h1 id="random-image-api-dan-public-gallery" tabindex="-1">Random Image API dan Public Gallery <a class="header-anchor" href="#random-image-api-dan-public-gallery" aria-label="Permalink to &quot;Random Image API dan Public Gallery&quot;">​</a></h1><p>Kedua fitur ini dikonfigurasi di:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings</span></span></code></pre></div><h2 id="random-image-api" tabindex="-1">Random Image API <a class="header-anchor" href="#random-image-api" aria-label="Permalink to &quot;Random Image API&quot;">​</a></h2><p>Random Image API mengembalikan satu file acak dari direktori yang dipilih. Fitur ini berguna untuk background situs, rotasi avatar, atau pemanggilan gambar acak dari halaman eksternal.</p><p>Setelah diaktifkan, gunakan:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/random</span></span></code></pre></div><h2 id="pengaturan-random-image-api" tabindex="-1">Pengaturan Random Image API <a class="header-anchor" href="#pengaturan-random-image-api" aria-label="Permalink to &quot;Pengaturan Random Image API&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Opsi</th><th>Fungsi</th></tr></thead><tbody><tr><td>Enable</td><td>Mengaktifkan atau menonaktifkan endpoint <code>/random</code>. Jika nonaktif, akses akan ditolak.</td></tr><tr><td>Directories</td><td>Membatasi direktori yang boleh dipakai random API. Direktori yang tidak ada di sini tidak bisa dipakai API.</td></tr><tr><td>Call demo</td><td>Membuat link random API yang bisa langsung disalin.</td></tr></tbody></table><p>Anda bisa memilih beberapa direktori. Misalnya hanya <code>/landscape/</code> dan <code>/portrait/</code> yang diizinkan, maka random API hanya bisa mengambil file dari direktori tersebut dan subdirektorinya.</p><h2 id="parameter-random-image-api" tabindex="-1">Parameter Random Image API <a class="header-anchor" href="#parameter-random-image-api" aria-label="Permalink to &quot;Parameter Random Image API&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Parameter</th><th>Contoh</th><th>Fungsi</th></tr></thead><tbody><tr><td><code>dir</code></td><td><code>/landscape/</code></td><td>Menentukan direktori acak.</td></tr><tr><td><code>content</code></td><td><code>image</code></td><td>Menentukan jenis media. Gunakan <code>image</code>, <code>video</code>, <code>audio</code>, atau kombinasi yang dipisahkan koma.</td></tr><tr><td><code>orientation</code></td><td><code>auto</code></td><td>Memfilter orientasi gambar. Gunakan <code>portrait</code>, <code>landscape</code>, atau <code>auto</code>.</td></tr><tr><td><code>type</code></td><td><code>url</code></td><td>Format respons. Kosong berarti redirect, <code>url</code> mengembalikan URL teks biasa, <code>json</code> mengembalikan JSON.</td></tr><tr><td><code>origin</code></td><td><code>1</code></td><td>Dipakai bersama <code>type=url</code> untuk mengembalikan URL lengkap.</td></tr><tr><td><code>age</code></td><td><code>all-ages,r12</code></td><td>Memfilter berdasarkan rating usia.</td></tr><tr><td><code>tag</code></td><td><code>wallpaper,sky</code></td><td>Hanya mengembalikan file yang memiliki tag tersebut.</td></tr><tr><td><code>ex</code></td><td><code>private</code></td><td>Mengecualikan file yang memiliki tag tersebut.</td></tr></tbody></table><h2 id="format-respons" tabindex="-1">Format Respons <a class="header-anchor" href="#format-respons" aria-label="Permalink to &quot;Format Respons&quot;">​</a></h2><p>Tanpa <code>type</code>, API akan redirect langsung ke URL file acak.</p><p>Dengan <code>type=url</code>, API mengembalikan URL dalam bentuk teks.</p><p>Dengan <code>type=json</code>, API mengembalikan informasi file, termasuk URL file, file ID, nama file, tipe file, tag, rating, dan metadata terkait.</p><h2 id="aturan-akses" tabindex="-1">Aturan Akses <a class="header-anchor" href="#aturan-akses" aria-label="Permalink to &quot;Aturan Akses&quot;">​</a></h2><p>Random Image API mengikuti aturan akses publik:</p><table tabindex="0"><thead><tr><th>Aturan</th><th>Dampak</th></tr></thead><tbody><tr><td>Directory restriction</td><td>Hanya file di direktori yang diizinkan yang bisa dipilih.</td></tr><tr><td>Blocklist</td><td>File dalam blocklist dikeluarkan dari kumpulan random.</td></tr><tr><td>Allowlist mode</td><td>Jika aktif, hanya file yang diizinkan untuk akses publik yang dikembalikan.</td></tr><tr><td>Age rating</td><td>Konten R12, R16, R18, dan sejenisnya difilter mengikuti access mode saat ini.</td></tr></tbody></table><p>Jika setelah difilter tidak ada file yang cocok, API akan mengembalikan hasil tidak ditemukan.</p><h2 id="cache" tabindex="-1">Cache <a class="header-anchor" href="#cache" aria-label="Permalink to &quot;Cache&quot;">​</a></h2><p>Random Image API menyimpan cache candidate pool direktori agar respons lebih cepat.</p><p>Setelah file berubah, ImgBed memperbarui versi cache direktori, dan request berikutnya akan membangun ulang candidate pool. Direktori kosong di-cache singkat untuk menghindari query berulang.</p><h2 id="public-gallery" tabindex="-1">Public Gallery <a class="header-anchor" href="#public-gallery" aria-label="Permalink to &quot;Public Gallery&quot;">​</a></h2><p>Public gallery menyediakan halaman browsing publik yang read-only untuk direktori yang Anda izinkan dilihat pengunjung.</p><p>Setelah diaktifkan, pengunjung bisa membuka:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/browse/directory-name</span></span></code></pre></div><h2 id="pengaturan-public-gallery" tabindex="-1">Pengaturan Public Gallery <a class="header-anchor" href="#pengaturan-public-gallery" aria-label="Permalink to &quot;Pengaturan Public Gallery&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Opsi</th><th>Fungsi</th></tr></thead><tbody><tr><td>Enable</td><td>Mengaktifkan atau menonaktifkan public gallery. Jika nonaktif, pengunjung tidak bisa membukanya.</td></tr><tr><td>Image loading mode</td><td>Mengatur apakah preview memakai gambar asli atau thumbnail.</td></tr><tr><td>Open directories</td><td>Menentukan direktori yang bisa diakses pengunjung.</td></tr></tbody></table><h2 id="image-loading-mode" tabindex="-1">Image Loading Mode <a class="header-anchor" href="#image-loading-mode" aria-label="Permalink to &quot;Image Loading Mode&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mode</th><th>Fungsi</th></tr></thead><tbody><tr><td>Original</td><td>Halaman pengunjung memuat file asli secara langsung.</td></tr><tr><td>Thumbnail</td><td>Halaman pengunjung lebih mengutamakan thumbnail agar lebih cepat.</td></tr></tbody></table><h2 id="open-directories" tabindex="-1">Open Directories <a class="header-anchor" href="#open-directories" aria-label="Permalink to &quot;Open Directories&quot;">​</a></h2><p>Open directories menentukan apa yang bisa dilihat pengunjung.</p><p>Contoh:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/,/2/,/landscape/,/portrait/</span></span></code></pre></div><p>Pengunjung kemudian bisa mengakses:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/browse/1</span></span>
<span class="line"><span>https://your-domain.com/browse/2</span></span>
<span class="line"><span>https://your-domain.com/browse/landscape</span></span>
<span class="line"><span>https://your-domain.com/browse/portrait</span></span></code></pre></div><p>Subdirektori juga bisa dibuka, misalnya <code>/2026/lucky/</code>. Pengunjung akan diblokir dari direktori yang tidak dibuka.</p><h2 id="fitur-public-gallery" tabindex="-1">Fitur Public Gallery <a class="header-anchor" href="#fitur-public-gallery" aria-label="Permalink to &quot;Fitur Public Gallery&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Fitur</th><th>Keterangan</th></tr></thead><tbody><tr><td>Browse directories</td><td>Melihat file dan subdirektori di direktori yang dibuka.</td></tr><tr><td>Search</td><td>Mencari berdasarkan nama file, file ID, atau tag.</td></tr><tr><td>Type filter</td><td>Memfilter gambar, video, audio, atau file lain.</td></tr><tr><td>Tag filter</td><td>Menyertakan atau mengecualikan tag tertentu.</td></tr><tr><td>Orientation filter</td><td>Memfilter gambar landscape atau portrait.</td></tr><tr><td>Time filter</td><td>Memfilter berdasarkan rentang waktu upload.</td></tr><tr><td>Extension filter</td><td>Memfilter berdasarkan ekstensi file.</td></tr><tr><td>Copy link</td><td>Menyalin link akses file.</td></tr><tr><td>Media preview</td><td>Melihat atau memutar gambar, video, dan audio di halaman pengunjung.</td></tr></tbody></table><h2 id="aturan-akses-public-gallery" tabindex="-1">Aturan Akses Public Gallery <a class="header-anchor" href="#aturan-akses-public-gallery" aria-label="Permalink to &quot;Aturan Akses Public Gallery&quot;">​</a></h2><p>Public gallery juga mengikuti aturan akses publik:</p><table tabindex="0"><thead><tr><th>Aturan</th><th>Dampak</th></tr></thead><tbody><tr><td>Open directories</td><td>Hanya direktori yang diizinkan yang ditampilkan.</td></tr><tr><td>Access mode</td><td>Konten difilter berdasarkan access mode rating usia saat ini.</td></tr><tr><td>Allowlist mode</td><td>Jika aktif, hanya file yang diizinkan untuk akses publik yang ditampilkan.</td></tr><tr><td>Blocklist</td><td>File dalam blocklist disembunyikan.</td></tr></tbody></table>`,43)])])}const g=t(n,[["render",r]]);export{m as __pageData,g as default};
